      "judul": "Bab ar-Rayyan: Puasa dan Pembinaan Jiwa Manusia",
      "penulis": "Tim Kajian Ramadhan",
      "tanggal": "19 Februari 2026",
      "createdAt": "2026-02-19",
      "popular": false,
