      "slug": "catatan-ramadhan-larangan-ihtikar-penimbunan-barang-dalam-perspektif-syariah",
      "judul": "Ramadan Notes: The Prohibition of Hoarding in the Perspective of Islamic Law",
      "penulis": "Tim Kajian Ramadhan",
      "tanggal": "3 March 2026",
      "createdAt": "2026-03-03",
      "popular": false,
      "featured": false,
      "kategori": "ramadhan",
      "subkategori": "catatan-ramadhan",
