      "id": "jalan-keselamatan-ilmu-taubat-dan-mengikuti-rasul",
      "slug": "jalan-keselamatan-ilmu-taubat-dan-mengikuti-rasul",
      "judul": "The Path of Salvation: Knowledge, Repentance, and Following the Messenger",
      "penulis": "Tasawuf Study Team",
      "tanggal": "10 February 2026",
      "createdAt": "2026-02-10",
