      "slug": "puasa-kewajiban-keutamaan-dan-adab-dalam-syariat-islam",
      "judul": "Fasting in Islamic Law: Obligation, Virtues, and Etiquette",
      "penulis": "Fiqh Study Team",
      "tanggal": "13 February 2026",
      "createdAt": "2026-02-13",
      "popular": false,
      "featured": false,
      "kategori": "ilmusyariah",
      "subkategori": "fiqh",
      "tag": "fiqhibadah",
      "bahasa": "en",
